21→// 战斗阶段枚举
22→UENUM(BlueprintType)
23→enum class EBattlePhase : uint8
24→{
25→	BP_EnemyPlanning   UMETA(DisplayName = "Enemy Planning"),
26→	BP_ActionPhase     UMETA(DisplayName = "Action Phase"),
27→	BP_RoundEnd        UMETA(DisplayName = "Round End")
28→};
