33→{
34→	TT_Grass   UMETA(DisplayName = "草地"),
35→	TT_Sand    UMETA(DisplayName = "沙地"),
36→	TT_Dirt    UMETA(DisplayName = "泥地"),
37→	TT_Stone   UMETA(DisplayName = "石地"),
38→	TT_Snow    UMETA(DisplayName = "雪地"),
39→	TT_Water   UMETA(DisplayName = "水域"),
40→	TT_Lava    UMETA(DisplayName = "熔岩"),
