45→// 敌人行动计划结构体
46→USTRUCT(BlueprintType)
47→struct FEnemyActionPlan
48→{
49→	GENERATED_BODY()
50→
51→	// 执行计划的敌方单位
52→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
53→	ALFPTacticsUnit* EnemyUnit = nullptr;
54→
55→	// 选定的技能
56→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
57→	ULFPSkillBase* PlannedSkill = nullptr;
58→
59→	// 目标单位（可能在行动前死亡）
60→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
61→	ALFPTacticsUnit* TargetUnit = nullptr;
62→
63→	// 技能瞄准的格子（= 目标单位规划时所在格子）
64→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
65→	ALFPHexTile* TargetTile = nullptr;
66→
67→	// 敌人移动到的施法位置
68→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
69→	ALFPHexTile* CasterPositionTile = nullptr;
70→
71→	// 技能生效范围内的格子（绝对位置）
72→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
73→	TArray<ALFPHexTile*> EffectAreaTiles;
74→
75→	// 计划是否有效
76→	UPROPERTY(VisibleAnywhere, BlueprintReadOnly, Category = "AI Plan")
77→	bool bIsValid = false;
78→
79→	void Reset()
80→	{
81→		EnemyUnit = nullptr;
82→		PlannedSkill = nullptr;
83→		TargetUnit = nullptr;
84→		TargetTile = nullptr;
85→		CasterPositionTile = nullptr;
86→		EffectAreaTiles.Empty();
87→		bIsValid = false;
88→	}
89→};
