 9→void ALFPTurnGameMode::StartPlay()
10→{
11→    // 从 GameInstance 读取战斗请求
12→    if (ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance()))
13→    {
14→        CachedBattleRequest = GI->ConsumeBattleRequest();
15→        if (CachedBattleRequest.bIsValid)
16→        {
17→            UE_LOG(LogTemp, Log, TEXT("战斗模式: 由世界地图触发，节点 %d, 地图 %s, 星级 %d"),
18→                CachedBattleRequest.SourceNodeID,
19→                *CachedBattleRequest.BattleMapName,
20→                CachedBattleRequest.StarRating);
21→        }
22→    }
23→
24→    // 生成回合管理器
25→    FActorSpawnParameters SpawnParams;
26→    SpawnParams.Owner = this;
27→
28→    ALFPTurnManager* TurnManager = GetWorld()->SpawnActor<ALFPTurnManager>(
29→        ALFPTurnManager::StaticClass(),
30→        FVector::ZeroVector,
31→        FRotator::ZeroRotator,
32→        SpawnParams
33→    );
34→
35→    if (TurnManager)
36→    {
37→        TurnManager->StartGame();
38→    }
39→
40→    Super::StartPlay();
41→
42→    // TODO: 如果有 BattleMapName，让 HexGridManager 加载对应 CSV
43→    // 这需要在 HexGridManager 生成后调用 LoadMapFromCSV
44→}
45→
46→void ALFPTurnGameMode::EndBattle(bool bVictory, bool bEscaped)
47→{
48→    ULFPGameInstance* GI = Cast<ULFPGameInstance>(GetGameInstance());
49→    if (!GI) return;
50→
51→    // 写回战斗结果
52→    FLFPBattleResult Result;
53→    Result.SourceNodeID = CachedBattleRequest.SourceNodeID;
54→    Result.bVictory = bVictory;
55→    Result.bEscaped = bEscaped;
56→
57→    // 胜利时传递捕获的单位
58→    if (bVictory)
59→    {
60→        Result.CapturedUnits = CapturedUnits;
61→    }
62→
63→    GI->SetBattleResult(Result);
64→
65→    // 返回世界地图
66→    if (CachedBattleRequest.bIsValid)
67→    {
68→        GI->TransitionToWorldMap(TEXT(""));
69→    }
70→}
71→
72→void ALFPTurnGameMode::RecordCapturedUnit(ALFPTacticsUnit* Unit)
73→{
74→    if (!Unit) return;
75→
76→    FLFPUnitEntry Entry = Unit->ToUnitEntry();
77→    if (Entry.IsValid())
78→    {
79→        CapturedUnits.Add(Entry);
80→        UE_LOG(LogTemp, Log, TEXT("捕获单位: %s, 阶级 %d"), *Entry.TypeID.ToString(), Entry.Tier);
81→    }
82→}
