 25→void ALFPTurnManager::StartGame()
 26→{
 27→    // 收集所有单位
 28→    TArray<AActor*> FoundActors;
 29→    UGameplayStatics::GetAllActorsOfClass(GetWorld(), ALFPTacticsUnit::StaticClass(), FoundActors);
 30→
 31→    // 转换为战术单位数组
 32→    for (AActor* Actor : FoundActors)
 33→    {
 34→        if (ALFPTacticsUnit* Unit = Cast<ALFPTacticsUnit>(Actor))
 35→        {
 36→            TurnOrderUnits.Add(Unit);
 37→        }
 38→    }
 39→
 40→    // 添加延迟后开始第一回合
 41→    FTimerHandle TimerHandle;
 42→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
 43→
 44→    // 初始化阵营 AP
 45→    FactionCurrentAP.Add(EUnitAffiliation::UA_Player, FactionInitialAP);
 46→    FactionCurrentAP.Add(EUnitAffiliation::UA_Enemy, FactionInitialAP);
 47→    FactionCurrentAP.Add(EUnitAffiliation::UA_Neutral, FactionInitialAP);
 48→}
 49→
 50→void ALFPTurnManager::BeginNewRound()
 51→{
 52→    CurrentRound++;
 53→    bIsInRound = true;
 54→
 55→    // 重置所有单位
 56→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
 57→    {
 58→        if (Unit && Unit->IsValidLowLevel())
 59→        {
 60→            Unit->ResetForNewRound();
 61→        }
 62→    }
 63→
 64→    // 按速度排序单位
 65→    SortUnitsBySpeed();
 66→
 67→    // 清空上一轮的敌人计划
 68→    EnemyActionPlans.Empty();
 69→    AllocatedSkills.Empty();
 70→
 71→    // 恢复阵营 AP
 72→    for (auto& Pair : FactionCurrentAP)
 73→    {
 74→        Pair.Value = FMath::Min(Pair.Value + FactionAPRecovery, FactionMaxAP);
 75→        OnFactionAPChanged.Broadcast(Pair.Key, Pair.Value);
 76→    }
 77→
 78→    // 进入敌人规划阶段
 79→    BeginEnemyPlanningPhase();
 80→}
 81→
 82→void ALFPTurnManager::EndCurrentRound()
 83→{
 84→    bIsInRound = false;
 85→
 86→    SetPhase(EBattlePhase::BP_RoundEnd);
 87→
 88→    // 通知玩家本回合结束
 89→    for (FConstPlayerControllerIterator It = GetWorld()->GetPlayerControllerIterator(); It; ++It)
 90→    {
 91→        if (ALFPTacticsPlayerController* PC = Cast<ALFPTacticsPlayerController>(*It))
 92→        {
 93→            PC->OnRoundEnded(CurrentRound);
 94→        }
 95→    }
 96→
 97→    // 添加延迟后开始新回合
 98→    FTimerHandle TimerHandle;
 99→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, this, &ALFPTurnManager::BeginNewRound, 0.5f, false);
100→}
