102→void ALFPTurnManager::SortUnitsBySpeed()
103→{
104→    // 按速度降序排序（速度高的先行动）
105→    // Todo: 速度相同时随机排序（玩家优先于AI）
106→    TurnOrderUnits.Sort([](const ALFPTacticsUnit& A, const ALFPTacticsUnit& B) {
107→        return A.GetSpeed() > B.GetSpeed();
108→        });
109→}
