111→// ==== 阶段管理 ====
112→
113→void ALFPTurnManager::SetPhase(EBattlePhase NewPhase)
114→{
115→    CurrentPhase = NewPhase;
116→    OnPhaseChanged.Broadcast(NewPhase);
117→}
118→
119→// ==== 敌人规划阶段 ====
120→
121→void ALFPTurnManager::BeginEnemyPlanningPhase()
122→{
123→    SetPhase(EBattlePhase::BP_EnemyPlanning);
124→
125→    // 过滤出存活的敌方单位，按速度排序
126→    PlanningOrderEnemies.Empty();
127→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
128→    {
129→        if (Unit && Unit->IsAlive() && Unit->IsEnemy())
130→        {
131→            PlanningOrderEnemies.Add(Unit);
132→        }
133→    }
134→
135→    // 敌方单位已按速度排序（继承自 TurnOrderUnits 的排序）
136→
137→    CurrentPlanningEnemyIndex = 0;
138→
139→    if (PlanningOrderEnemies.Num() == 0)
140→    {
141→        // 没有敌方单位，直接进入行动阶段
142→        EndEnemyPlanningPhase();
143→        return;
144→    }
145→
146→    // 隐藏玩家技能选择UI
147→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
148→    {
149→        PC->HideSkillSelection();
150→    }
151→
152→    // Step 1: 全局技能分配（按优先级分配AP技能）
153→    AllocateEnemySkills();
154→
155→    // Step 2: 按速度顺序移动展示
156→    ProcessNextEnemyPlan();
157→}
158→
159→void ALFPTurnManager::ProcessNextEnemyPlan()
160→{
161→    if (CurrentPlanningEnemyIndex >= PlanningOrderEnemies.Num())
162→    {
163→        // 所有敌人规划完毕
164→        EndEnemyPlanningPhase();
165→        return;
166→    }
167→
168→    ALFPTacticsUnit* Enemy = PlanningOrderEnemies[CurrentPlanningEnemyIndex];
169→
170→    // 跳过死亡单位
171→    if (!Enemy || !Enemy->IsAlive())
172→    {
173→        CurrentPlanningEnemyIndex++;
174→        ProcessNextEnemyPlan();
175→        return;
176→    }
177→
178→    ALFPAIController* AIController = Enemy->GetAIController();
179→    if (!AIController)
180→    {
181→        CurrentPlanningEnemyIndex++;
182→        ProcessNextEnemyPlan();
183→        return;
184→    }
185→
186→    // 创建行动计划，传入预分配的技能
187→    ULFPSkillBase* PreAllocatedSkill = nullptr;
188→    if (ULFPSkillBase** Found = AllocatedSkills.Find(Enemy))
189→    {
190→        PreAllocatedSkill = *Found;
191→    }
192→    FEnemyActionPlan Plan = AIController->CreateActionPlan(PreAllocatedSkill);
193→
194→    // 存储计划
195→    EnemyActionPlans.Add(Plan);
196→    Enemy->SetActionPlan(Plan);
197→
198→    // 推进到下一个敌人，加延时让玩家观察
199→    CurrentPlanningEnemyIndex++;
200→    FTimerHandle TimerHandle;

200→    FTimerHandle TimerHandle;
201→    GetWorld()->GetTimerManager().SetTimer(
202→        TimerHandle,
203→        this,
204→        &ALFPTurnManager::ProcessNextEnemyPlan,
205→        0.5f,
206→        false
207→    );
208→}
209→
210→void ALFPTurnManager::EndEnemyPlanningPhase()
211→{
212→    BeginActionPhase();
213→}
214→
215→// ==== 行动阶段 ====
216→
217→void ALFPTurnManager::BeginActionPhase()
218→{
219→    SetPhase(EBattlePhase::BP_ActionPhase);
220→
221→    // 开始第一个单位的回合
222→    if (TurnOrderUnits.Num() > 0)
223→    {
224→        BeginUnitTurn(TurnOrderUnits[0]);
225→    }
226→}
227→
228→void ALFPTurnManager::BeginUnitTurn(ALFPTacticsUnit* Unit)
229→{
230→    OnTurnChanged.Broadcast();
231→
232→    CurrentUnit = Unit;
233→
234→    ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>();
235→
236→    // 敌方单位在行动阶段：执行预定计划
237→    if (Unit->IsEnemy() && CurrentPhase == EBattlePhase::BP_ActionPhase)
238→    {
239→        if (PC)
240→        {
241→            PC->HideSkillSelection();
242→        }
243→
244→        Unit->OnTurnStarted();
245→
246→        ExecuteEnemyPlan(Unit);
247→        return;
248→    }
249→
250→    // 玩家单位：保持原有逻辑
251→    if (Unit)
252→    {
253→        Unit->OnTurnStarted();
254→    }
255→
256→    if (PC)
257→    {
258→        PC->OnTurnStarted(Unit);
259→        PC->SelectUnit(Unit);
260→        PC->HandleSkillSelection();
261→    }
262→}
263→
264→void ALFPTurnManager::ExecuteEnemyPlan(ALFPTacticsUnit* Unit)
265→{
266→    const FEnemyActionPlan& Plan = GetPlanForEnemy(Unit);
267→
268→    if (Plan.bIsValid && Plan.PlannedSkill)
269→    {
270→        // 在原定目标格子释放技能（即使目标已死亡）
271→        // AP 已在规划阶段 AllocateEnemySkills 中扣除
272→        Unit->ExecuteSkill(Plan.PlannedSkill, Plan.TargetTile);
273→    }
274→
275→    // 清除头顶技能图标
276→    Unit->ClearActionPlan();
277→
278→    // 短延时后结束回合（让玩家看到技能效果）
279→    FTimerHandle TimerHandle;
280→    GetWorld()->GetTimerManager().SetTimer(TimerHandle, [this, Unit]()
281→    {
282→        Unit->SetHasActed(true);
283→        PassTurn();
284→    }, 0.5f, false);
285→}
286→
287→void ALFPTurnManager::EndUnitTurn(ALFPTacticsUnit* Unit)
288→{
289→    if (Unit)
290→    {
291→        Unit->OnTurnEnded();
292→    }
293→
294→    // 通知玩家控制器
295→    if (ALFPTacticsPlayerController* PC = GetWorld()->GetFirstPlayerController<ALFPTacticsPlayerController>())
296→    {
297→        PC->OnTurnEnded(Unit);
298→    }
299→}
300→
301→void ALFPTurnManager::PassTurn()
302→{
303→    if (!CurrentUnit || TurnOrderUnits.IsEmpty())
304→    {
305→        return;
306→    }
307→
308→    // 结束当前单位回合
309→    EndUnitTurn(CurrentUnit);
310→
311→    // 找到下一个未行动的单位
312→    int32 CurrentIndex = TurnOrderUnits.Find(CurrentUnit);
313→    int32 NextIndex = (CurrentIndex + 1) % TurnOrderUnits.Num();
314→
315→    // 检查所有单位是否行动完毕
316→    bool TurnOrderUnitsActed = true;
317→    for (ALFPTacticsUnit* Unit : TurnOrderUnits)
318→    {
319→        if (Unit && Unit->IsAlive() && !Unit->HasActed())
320→        {
321→            TurnOrderUnitsActed = false;
322→            break;
323→        }
324→    }
325→
326→    if (TurnOrderUnitsActed)
327→    {
328→        // 所有单位行动完毕，结束回合
329→        EndCurrentRound();
330→    }
331→    else
332→    {
333→        // 寻找下一个未行动单位
334→        for (int32 i = 0; i < TurnOrderUnits.Num(); i++)
335→        {
336→            int32 Index = (NextIndex + i) % TurnOrderUnits.Num();
337→            ALFPTacticsUnit* NextUnit = TurnOrderUnits[Index];
338→
339→            if (NextUnit && NextUnit->IsAlive() && !NextUnit->HasActed())
340→            {
341→                BeginUnitTurn(NextUnit);
342→                return;
343→            }
344→        }
345→
346→        // 没有找到未行动单位，结束回合
347→        EndCurrentRound();
348→    }
349→}

